package com.example.secondphone.security;
import java.io.IOException;import org.springframework.http.MediaType;import org.springframework.security.core.AuthenticationException;import org.springframework.security.web.AuthenticationEntryPoint;import org.springframework.stereotype.Component;import com.fasterxml.jackson.databind.ObjectMapper;import com.example.secondphone.exception.ApiErrorResponse;import jakarta.servlet.http.*;
@Component public class RestAuthenticationEntryPoint implements AuthenticationEntryPoint{private final ObjectMapper mapper;public RestAuthenticationEntryPoint(ObjectMapper mapper){this.mapper=mapper;}@Override public void commence(HttpServletRequest request,HttpServletResponse response,AuthenticationException exception)throws IOException{response.setStatus(401);response.setContentType(MediaType.APPLICATION_JSON_VALUE);mapper.writeValue(response.getOutputStream(),ApiErrorResponse.of("請先登入",request.getRequestURI()));}}
